import { verifyCredential } from "./credentialVerifier.js";
import { getPool } from "../db/pool.js";

/**
 * Verify a delegation chain and ensure proper attenuation at each step.
 *
 * @param {string[]} credentials - array of JWT strings, root-first (index 0 = root, last = leaf)
 * @param {string} presenterId - authenticated presenter identity
 * @param {object} options - verification options
 * @returns {object} { verified, payload (leaf normalized payload), chainDepth, error?, errorCode? }
 */
export async function verifyDelegationChain(credentials, presenterId, options = {}) {
  const pool = getPool();

  // Fetch delegation config
  const { rows: configRows } = await pool.query(
    `SELECT key, value FROM portauth_delegation_config`
  );
  const config = Object.fromEntries(configRows.map(r => [r.key, r.value]));
  const maxDepth = parseInt(config.max_depth || "5", 10);
  const requireAttenuation = config.require_attenuation_proof !== "false";

  if (credentials.length > maxDepth) {
    return {
      verified: false,
      error: `Delegation chain depth ${credentials.length} exceeds maximum ${maxDepth}`,
      errorCode: "delegation_depth_exceeded",
    };
  }

  let parentPayload = null;
  let leafPayload = null;

  for (let i = 0; i < credentials.length; i++) {
    const isLeaf = i === credentials.length - 1;

    // For the root, verify with full issuer trust check.
    // For delegates, the presenter binding applies only to the leaf.
    const effectivePresenterId = isLeaf ? presenterId : null;

    const result = await verifyCredential(credentials[i], effectivePresenterId, {
      ...options,
      skipProofOfPossession: !isLeaf || options.skipProofOfPossession,
    });

    if (!result.verified) {
      return {
        verified: false,
        error: `Chain link ${i} verification failed: ${result.error}`,
        errorCode: result.errorCode === "issuer_untrusted" && i !== 0 ? "delegation_chain_broken" : result.errorCode,
        chainDepth: i,
      };
    }

    const payload = result.payload;

    // For non-root links, verify issuer-subject continuity and attenuation.
    if (parentPayload) {
      const continuityResult = validateDelegationLink(parentPayload, payload);
      if (!continuityResult.valid) {
        return {
          verified: false,
          error: continuityResult.reason,
          errorCode: "delegation_chain_broken",
          chainDepth: i,
        };
      }

      if (requireAttenuation) {
        const attenuationResult = verifyAttenuation(parentPayload, payload);
        if (!attenuationResult.valid) {
          return {
            verified: false,
            error: attenuationResult.reason,
            errorCode: "delegation_widened",
            chainDepth: i,
          };
        }
      }
    }

    parentPayload = payload;
    if (isLeaf) leafPayload = payload;
  }

  return {
    verified: true,
    payload: leafPayload,
    chainDepth: credentials.length,
  };
}

export function validateDelegationLink(parentPayload, delegatePayload) {
  if (delegatePayload.issuerId !== parentPayload.agentId) {
    return {
      valid: false,
      reason: `Delegation issuer-subject continuity failed: expected child issuer ${parentPayload.agentId}, got ${delegatePayload.issuerId}`,
    };
  }

  if (!delegatePayload.delegatedFrom) {
    return {
      valid: false,
      reason: `Delegation link missing delegatedFrom reference to parent credential ${parentPayload.credentialId}`,
    };
  }

  if (delegatePayload.delegatedFrom !== parentPayload.credentialId) {
    return {
      valid: false,
      reason: `delegatedFrom mismatch: expected ${parentPayload.credentialId}, got ${delegatePayload.delegatedFrom}`,
    };
  }

  return { valid: true };
}

/**
 * Verify that a delegate's payload is a proper attenuation of the parent's.
 * Permissions can only be narrowed (subset). Constraints can only be tightened (more restrictive).
 */
export function verifyAttenuation(parent, delegate) {
  // 1. Permissions must be a subset
  const extraPerms = delegate.permissions.filter(p => !parent.permissions.includes(p));
  if (extraPerms.length > 0) {
    return { valid: false, reason: `Delegation widened: added permissions [${extraPerms.join(", ")}] not in parent` };
  }

  // 2. For each constraint type/field in parent, delegate must have equal-or-tighter
  // Constraints that parent has but delegate drops → inherited from parent (delegate cannot drop)
  for (const parentConstraint of parent.constraints) {
    const matchingDelegate = delegate.constraints.find(dc => constraintsSameTarget(parentConstraint, dc));

    if (!matchingDelegate) {
      // Delegate dropped a constraint — this is widening
      return { valid: false, reason: `Delegation dropped constraint: ${parentConstraint.type} on field '${parentConstraint.field}'` };
    }

    const check = isMoreRestrictive(parentConstraint, matchingDelegate);
    if (!check.valid) {
      return { valid: false, reason: `Delegation widened constraint ${parentConstraint.type} on '${parentConstraint.field}': ${check.reason}` };
    }
  }

  return { valid: true };
}

function constraintsSameTarget(parent, delegate) {
  if (delegate.type !== parent.type) return false;
  if (parent.id || delegate.id) return parent.id === delegate.id;
  return delegate.field === parent.field;
}

/**
 * Check that delegateConstraint is equal-or-more-restrictive than parentConstraint.
 */
function isMoreRestrictive(parent, delegate) {
  switch (parent.type) {
    case "NumericLimitConstraint":
      return numericAttenuation(parent, delegate);
    case "TemporalWindowConstraint":
      return temporalAttenuation(parent, delegate);
    case "EnumeratedListConstraint":
      return enumeratedAttenuation(parent, delegate);
    case "StringPatternConstraint":
      return stringPatternAttenuation(parent, delegate);
    case "CumulativeLimitConstraint":
      return cumulativeLimitAttenuation(parent, delegate);
    case "UsageLimitConstraint":
      return usageLimitAttenuation(parent, delegate);
    default:
      return { valid: false, reason: `Cannot verify attenuation for unknown type ${parent.type}` };
  }
}

function valueOfLimit(constraint, keys) {
  for (const key of keys) {
    if (constraint[key] !== undefined) return Number(constraint[key]);
  }
  return NaN;
}

function sameStatefulWindow(parent, delegate) {
  if ((delegate.period || "forever") !== (parent.period || "forever")) {
    return { valid: false, reason: `Period changed from ${parent.period || "forever"} to ${delegate.period || "forever"}` };
  }
  if ((delegate.scope || "credential") !== (parent.scope || "credential")) {
    return { valid: false, reason: `Scope changed from ${parent.scope || "credential"} to ${delegate.scope || "credential"}` };
  }
  return { valid: true };
}

function cumulativeLimitAttenuation(parent, delegate) {
  if (parent.field !== delegate.field) {
    return { valid: false, reason: `Field changed from ${parent.field} to ${delegate.field}` };
  }
  const windowCheck = sameStatefulWindow(parent, delegate);
  if (!windowCheck.valid) return windowCheck;

  const parentLimit = valueOfLimit(parent, ["maxAmount", "value", "limit"]);
  const delegateLimit = valueOfLimit(delegate, ["maxAmount", "value", "limit"]);
  if (!Number.isFinite(parentLimit) || !Number.isFinite(delegateLimit)) {
    return { valid: false, reason: "Cumulative limit missing maxAmount/value/limit" };
  }
  if (delegateLimit > parentLimit) {
    return { valid: false, reason: `Delegate raised cumulative limit from ${parentLimit} to ${delegateLimit}` };
  }
  return { valid: true };
}

function usageLimitAttenuation(parent, delegate) {
  const windowCheck = sameStatefulWindow(parent, delegate);
  if (!windowCheck.valid) return windowCheck;

  const parentLimit = valueOfLimit(parent, ["maxUses", "value", "limit"]);
  const delegateLimit = valueOfLimit(delegate, ["maxUses", "value", "limit"]);
  if (!Number.isFinite(parentLimit) || !Number.isFinite(delegateLimit)) {
    return { valid: false, reason: "Usage limit missing maxUses/value/limit" };
  }
  if (delegateLimit > parentLimit) {
    return { valid: false, reason: `Delegate raised usage limit from ${parentLimit} to ${delegateLimit}` };
  }
  return { valid: true };
}

function numericAttenuation(parent, delegate) {
  // For lte/lt: delegate value must be <= parent value
  // For gte/gt: delegate value must be >= parent value
  if (parent.operator !== delegate.operator) {
    return { valid: false, reason: `Operator changed from ${parent.operator} to ${delegate.operator}` };
  }
  switch (parent.operator) {
    case "lte": case "lt":
      if (delegate.value > parent.value) return { valid: false, reason: `Delegate raised limit from ${parent.value} to ${delegate.value}` };
      break;
    case "gte": case "gt":
      if (delegate.value < parent.value) return { valid: false, reason: `Delegate lowered floor from ${parent.value} to ${delegate.value}` };
      break;
    case "eq":
      if (delegate.value !== parent.value) return { valid: false, reason: `Delegate changed exact value from ${parent.value} to ${delegate.value}` };
      break;
  }
  return { valid: true };
}

function temporalAttenuation(parent, delegate) {
  // validFrom can be equal or later; validUntil can be equal or earlier; daysOfWeek must be subset
  if (delegate.validFrom && parent.validFrom) {
    const [dh, dm] = delegate.validFrom.split(":").map(Number);
    const [ph, pm] = parent.validFrom.split(":").map(Number);
    if (dh * 60 + (dm || 0) < ph * 60 + (pm || 0)) {
      return { valid: false, reason: `Delegate start time ${delegate.validFrom} is earlier than parent ${parent.validFrom}` };
    }
  }
  if (delegate.validUntil && parent.validUntil) {
    const [dh, dm] = delegate.validUntil.split(":").map(Number);
    const [ph, pm] = parent.validUntil.split(":").map(Number);
    if (dh * 60 + (dm || 0) > ph * 60 + (pm || 0)) {
      return { valid: false, reason: `Delegate end time ${delegate.validUntil} is later than parent ${parent.validUntil}` };
    }
  }
  if (delegate.daysOfWeek && parent.daysOfWeek) {
    const extra = delegate.daysOfWeek.filter(d => !parent.daysOfWeek.includes(d));
    if (extra.length > 0) {
      return { valid: false, reason: `Delegate added days [${extra.join(", ")}] not in parent` };
    }
  }
  return { valid: true };
}

function enumeratedAttenuation(parent, delegate) {
  // Delegate's allowed must be subset of parent's allowed
  if (delegate.allowed && parent.allowed) {
    const extra = delegate.allowed.filter(v => !parent.allowed.includes(v));
    if (extra.length > 0) {
      return { valid: false, reason: `Delegate added allowed values [${extra.join(", ")}] not in parent` };
    }
  }
  // Delegate's denied may be superset (more restrictive)
  if (parent.denied && delegate.denied) {
    const missing = parent.denied.filter(v => !delegate.denied.includes(v));
    if (missing.length > 0) {
      return { valid: false, reason: `Delegate removed denied values [${missing.join(", ")}] from parent` };
    }
  }
  return { valid: true };
}

function stringPatternAttenuation(parent, delegate) {
  if (parent.matchType !== delegate.matchType) {
    return { valid: false, reason: `Match type changed from ${parent.matchType} to ${delegate.matchType}` };
  }
  switch (parent.matchType) {
    case "exact":
      if (delegate.pattern !== parent.pattern) return { valid: false, reason: `Exact pattern changed` };
      break;
    case "prefix":
      if (!delegate.pattern.startsWith(parent.pattern)) return { valid: false, reason: `Delegate prefix '${delegate.pattern}' is not a refinement of parent '${parent.pattern}'` };
      break;
    case "suffix":
      if (!delegate.pattern.endsWith(parent.pattern)) return { valid: false, reason: `Delegate suffix '${delegate.pattern}' is not a refinement of parent '${parent.pattern}'` };
      break;
    case "restricted_glob": {
      if (!isRestrictedGlobRefinement(parent.pattern, delegate.pattern)) {
        return { valid: false, reason: `Delegate glob '${delegate.pattern}' does not refine parent '${parent.pattern}'` };
      }
      break;
    }
  }
  return { valid: true };
}

/**
 * Restricted-glob alphabet (Plan 5):
 *   `*`  matches any sequence of characters that does not include `/`
 *   `**` matches any sequence of characters (including `/`)
 *   any other character matches itself literally
 *
 * Returns true iff every string matched by `delegate` is also matched by
 * `parent` (i.e. delegate's language is a subset of parent's). The check is
 * sound (never false-accepts) but intentionally conservative: it compares the
 * two patterns segment-by-segment (split on `/`) and within each segment uses
 * the rules below. A future iteration may switch to a full regex-subset test.
 */
export function isRestrictedGlobRefinement(parent, delegate) {
  if (parent === delegate) return true;

  // Splitting on `/` is sound because `*` cannot cross a separator. `**`
  // segments are treated as "match zero or more whole segments".
  const parentSegs = parent.split("/");
  const delegateSegs = delegate.split("/");
  return segmentSubset(parentSegs, delegateSegs);
}

function segmentSubset(parentSegs, delegateSegs) {
  // Each `**` segment in the parent can absorb zero or more delegate segments;
  // every other parent segment must align with exactly one delegate segment
  // and must dominate it under intra-segment matching.
  let i = 0; // parent index
  let j = 0; // delegate index

  while (i < parentSegs.length && j < delegateSegs.length) {
    const p = parentSegs[i];
    if (p === "**") {
      // ** absorbs any tail; try to match the rest of the pattern (i+1..)
      // against any suffix of the delegate (j..delegateSegs.length).
      if (i === parentSegs.length - 1) return true; // trailing ** matches anything
      for (let k = j; k <= delegateSegs.length; k++) {
        if (segmentSubset(parentSegs.slice(i + 1), delegateSegs.slice(k))) {
          return true;
        }
      }
      return false;
    }

    // The delegate's segment cannot itself be `**` unless the parent's
    // segment is also `**`, because `**` widens scope.
    if (delegateSegs[j] === "**") return false;

    if (!intraSegmentSubset(p, delegateSegs[j])) return false;
    i += 1;
    j += 1;
  }

  // Allow trailing parent `**` segments to be empty.
  while (i < parentSegs.length && parentSegs[i] === "**") i += 1;

  return i === parentSegs.length && j === delegateSegs.length;
}

/**
 * True iff every string matched by `delegateSeg` is matched by `parentSeg`,
 * where `*` inside a segment matches any character sequence except `/`.
 * Conservative: if the delegate introduces wildcards in positions the parent
 * does not, returns false.
 */
function intraSegmentSubset(parentSeg, delegateSeg) {
  if (parentSeg === delegateSeg) return true;

  // Compile both to anchored regexes over the alphabet [^/] and run a small
  // subset check: language(delegate) is a subset of language(parent) iff
  // language(delegate) intersect complement(parent) is empty. Computing the
  // intersection of two NFAs is overkill here; instead we use the structural
  // observation that delegate refines parent only if delegate's literal
  // chunks each align inside one of parent's wildcards.
  const parentTokens = tokenizeSegment(parentSeg);
  const delegateTokens = tokenizeSegment(delegateSeg);
  return tokenSubset(parentTokens, delegateTokens);
}

function tokenizeSegment(seg) {
  // Returns an array of tokens: either {star: true} or {literal: "..."}.
  const tokens = [];
  let buf = "";
  for (const ch of seg) {
    if (ch === "*") {
      if (buf) { tokens.push({ literal: buf }); buf = ""; }
      // Collapse consecutive stars within a segment to a single star
      if (!tokens.length || !tokens[tokens.length - 1].star) {
        tokens.push({ star: true });
      }
    } else {
      buf += ch;
    }
  }
  if (buf) tokens.push({ literal: buf });
  return tokens;
}

function tokenSubset(parentTokens, delegateTokens) {
  // Reject any delegate `*` that is not contained inside a parent `*`. We
  // achieve this by matching delegate's literals greedily under parent's
  // structure; if a delegate `*` appears at a position where the parent
  // requires a literal, the parent does not dominate the delegate.

  // Build the regex parent matches against (anchored, [^/] alphabet).
  const parentRegex = compileSegmentRegex(parentTokens);
  // The set of strings delegate matches is itself characterized by its
  // tokens. We over-approximate "every string delegate matches" by checking
  // two facts:
  //   1. The delegate's exact concatenation of literals (replacing each `*`
  //      with the empty string) matches the parent.
  //   2. The delegate's concatenation with a sentinel string at each `*`
  //      position also matches.
  // If both hold and the delegate has no `*` outside the spans where the
  // parent has `*`, the delegate is a refinement.
  const allLiterals = delegateTokens.filter(t => t.literal).map(t => t.literal).join("");
  if (!parentRegex.test(allLiterals)) return false;
  const withSentinel = delegateTokens.map(t => t.literal || "x").join("");
  if (!parentRegex.test(withSentinel)) return false;

  // Reject when delegate has more wildcards than parent (structural widening).
  const parentStars = parentTokens.filter(t => t.star).length;
  const delegateStars = delegateTokens.filter(t => t.star).length;
  if (delegateStars > parentStars) return false;
  return true;
}

function compileSegmentRegex(tokens) {
  const escape = (s) => s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const body = tokens.map(t => t.star ? "[^/]*" : escape(t.literal)).join("");
  return new RegExp(`^${body}$`);
}
